def binary_search_ceiling(arr, target):
    low = 0
    high = len(arr) - 1
    ans_idx = len(arr)
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] >= target:
            ans_idx = mid
            high = mid - 1
        else:
            low = mid + 1
    return ans_idx

def binary_search_floor(arr, target):
    low = 0
    high = len(arr) - 1
    ans_idx = -1
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] <= target:
            ans_idx = mid
            low = mid + 1
        else:
            high = mid - 1
    return ans_idx

def binary_search_rotated(arr, target):
    low = 0
    high = len(arr) - 1
    while low <= high:
        mid = low + (high - low) // 2
        if arr[mid] == target:
            return mid

        if arr[low] <= arr[mid]:  # Left half is sorted
            if arr[low] <= target < arr[mid]:
                high = mid - 1
            else:
                low = mid + 1
        else:  # Right half is sorted
            if arr[mid] < target <= arr[high]:
                low = mid + 1
            else:
                high = mid - 1
    return -1
